
import React, { useState, useRef, useEffect } from 'react';
import { ImageUploader } from './components/ImageUploader';
import { WajhCanvas } from './components/WajhCanvas';
import AdminDashboard from './components/AdminDashboard';
import { FaceLandmarkService } from './services/FaceLandmarks';
import { RotateCcw, LayoutDashboard } from 'lucide-react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import Login from './pages/Login';
import Register from './pages/Register';
import PatientView from './pages/PatientView';

const LOGO_SRC = "data:image/jpeg;base64,";

// ── Splash Screen Component ───────────────────────────────────────
function SplashScreen({ onDone }) {
  const [phase, setPhase] = useState('logo');   // logo → tagline → exit

  useEffect(() => {
    const t1 = setTimeout(() => setPhase('tagline'), 1200);
    const t2 = setTimeout(() => setPhase('exit'),    2800);
    const t3 = setTimeout(() => onDone(),            3600);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, [onDone]);

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 9999,
      background: '#0a0e17',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      transition: 'opacity 0.8s ease',
      opacity: phase === 'exit' ? 0 : 1,
    }}>
      {/* Logo image */}
      <div style={{
        transition: 'all 0.9s cubic-bezier(0.34, 1.56, 0.64, 1)',
        transform: phase === 'logo' ? 'scale(0.6)' : 'scale(1)',
        opacity: phase === 'logo' ? 0 : 1,
        filter: 'drop-shadow(0 0 40px rgba(56,189,248,0.3))',
      }}>
        <img
          src={LOGO_SRC}
          alt="WAJH Logo"
          style={{
            width: 260, height: 'auto',
            borderRadius: 16,
            filter: 'brightness(0.9) contrast(1.1)',
          }}
        />
      </div>

      {/* Tagline */}
      <div style={{
        marginTop: 8,
        transition: 'all 0.7s ease 0.4s',
        opacity: phase === 'tagline' || phase === 'exit' ? 1 : 0,
        transform: phase === 'tagline' || phase === 'exit' ? 'translateY(0)' : 'translateY(12px)',
        textAlign: 'center',
      }}>
        <div style={{
          fontSize: '1rem', color: '#64748b',
          letterSpacing: '0.15em', textTransform: 'uppercase',
          fontFamily: 'DM Sans, sans-serif', fontWeight: 500,
        }}>
          Maxillofacial Surgical Planning
        </div>
        <div style={{
          width: 60, height: 2,
          background: 'linear-gradient(90deg, transparent, #38bdf8, transparent)',
          margin: '12px auto 0',
          borderRadius: 2,
        }} />
      </div>

      {/* Loading dots */}
      <div style={{
        position: 'absolute', bottom: 48,
        display: 'flex', gap: 8,
        transition: 'opacity 0.5s ease 0.8s',
        opacity: phase === 'tagline' || phase === 'exit' ? 1 : 0,
      }}>
        {[0, 1, 2].map(i => (
          <div key={i} style={{
            width: 7, height: 7, borderRadius: '50%',
            background: '#38bdf8',
            animation: `pulse 1.2s ease-in-out ${i * 0.2}s infinite`,
            opacity: 0.6,
          }} />
        ))}
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { transform: scale(1); opacity: 0.4; }
          50% { transform: scale(1.4); opacity: 1; }
        }
      `}</style>
    </div>
  );
}

// ── Core Application Workspace Component (The Missing Link) ──────
function App() {
  const [showSplash, setShowSplash] = useState(true);
  const [showAdmin, setShowAdmin] = useState(false);

  // ── Upload → Detect → Canvas pipeline ──────────────────────────
  // This was previously disconnected: ImageUploader had no onImageUpload
  // handler (it would throw when a file was dropped), and WajhCanvas was
  // rendered unconditionally without ever receiving an image, so the upload
  // panel and the surgical workspace showed at the same time instead of
  // one after the other.
  const [uploadedImage, setUploadedImage] = useState(null);
  const [landmarks, setLandmarks] = useState(null);
  const [meshLandmarks, setMeshLandmarks] = useState(null);
  const [isDetecting, setIsDetecting] = useState(false);
  const [detectionError, setDetectionError] = useState('');

  const landmarkServiceRef = useRef(null);
  if (!landmarkServiceRef.current) {
    landmarkServiceRef.current = new FaceLandmarkService();
  }

  const handleImageUpload = (dataUrl) => {
    setDetectionError('');
    setIsDetecting(true);

    const img = new Image();
    img.onload = async () => {
      try {
        const result = await landmarkServiceRef.current.detect(img);
        if (!result) {
          setDetectionError('No face detected in this photo. Try a clear, front-facing photo with good lighting.');
          setIsDetecting(false);
          return;
        }
        setLandmarks(result.keyPoints);
        setMeshLandmarks(result.allLandmarks);
        setUploadedImage(dataUrl);
      } catch (e) {
        setDetectionError(e?.message || 'Face detection failed. Please try again.');
      } finally {
        setIsDetecting(false);
      }
    };
    img.onerror = () => {
      setDetectionError('Could not load that image file.');
      setIsDetecting(false);
    };
    img.src = dataUrl;
  };

  const handleNewPatient = () => {
    setUploadedImage(null);
    setLandmarks(null);
    setMeshLandmarks(null);
    setDetectionError('');
  };

  return (
    <>
      {showSplash && <SplashScreen onDone={() => setShowSplash(false)} />}
      
      <div className="min-h-screen bg-[#0a0e17] text-white flex flex-col">
        {/* Top Header / Navbar */}
        <header className="border-b border-white/10 px-6 py-4 flex items-center justify-between bg-[#0e1420]">
          <div className="flex items-center gap-3">
            <span className="font-serif text-xl tracking-widest text-white uppercase">WAJH</span>
            <span className="text-xs text-white/40 tracking-wider border-l border-white/20 pl-3 hidden sm:inline">
              Maxillofacial Planning Environment
            </span>
          </div>

          <div className="flex items-center gap-3">
            {uploadedImage && !showAdmin && (
              <button
                onClick={handleNewPatient}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-sm tracking-wide transition-colors border border-white/5"
              >
                <RotateCcw size={16} />
                New Patient
              </button>
            )}
            <button 
              onClick={() => setShowAdmin(!showAdmin)}
              className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-sm tracking-wide transition-colors border border-white/5"
            >
              <LayoutDashboard size={16} />
              {showAdmin ? "Workspace" : "Admin Dashboard"}
            </button>
          </div>
        </header>

        {/* Dynamic Workspace Switcher */}
        <main className="flex-1 relative p-6">
          {showAdmin ? (
            <AdminDashboard />
          ) : uploadedImage ? (
            // Step 2: Surgical workspace — WajhCanvas lays out its own
            // Surgical Controls / Canvas / Simulation columns internally,
            // so it needs the full width here, not a shared grid column.
            <div className="bg-[#0e1420] rounded-xl border border-white/5 overflow-hidden shadow-2xl h-full min-h-[600px]">
              <WajhCanvas
                imageSrc={uploadedImage}
                initialLandmarks={landmarks}
                initialMeshLandmarks={meshLandmarks}
              />
            </div>
          ) : (
            // Step 1: Upload landing page
            <div className="flex flex-col items-center justify-center text-center gap-6 max-w-xl mx-auto py-10">
              <img src={LOGO_SRC} alt="WAJH" style={{ width: 140, height: 'auto', borderRadius: 16 }} />
              <h1 className="text-4xl font-bold leading-tight">
                Maxillofacial<br />
                <span className="bg-gradient-to-r from-sky-400 to-violet-400 bg-clip-text text-transparent">Morphology</span> Surgical Prediction
              </h1>
              <p className="text-white/40 text-sm">
                Intelligent reconstructive simulation for post-maxillofacial skeletal procedures
              </p>

              <div className="bg-[#0e1420] rounded-xl border border-white/5 p-6 shadow-2xl w-full">
                {isDetecting ? (
                  <div className="flex flex-col items-center gap-3 py-6">
                    <div className="spinner" />
                    <p className="text-sm text-white/60">Detecting facial landmarks...</p>
                  </div>
                ) : (
                  <ImageUploader onImageUpload={handleImageUpload} />
                )}
                {detectionError && (
                  <p className="text-red-400 text-xs mt-4">{detectionError}</p>
                )}
              </div>
            </div>
          )}
        </main>
      </div>
    </>
  );
}

// ── Role-based workspace switch ────────────────────────────────────
// DOCTOR accounts get the full surgical planning workspace; PATIENT
// accounts get the read-only Patient View (their result + doctor notes).
function Workspace() {
  const { user } = useAuth();
  return user?.role === 'PATIENT' ? <PatientView /> : <App />;
}

// ── Main App Root Wrapper ─────────────────────────────────────────
export default function AppWithAuth() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/*" element={
            <ProtectedRoute>
              <Workspace />
            </ProtectedRoute>
          } />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}